-- Projects & integrations schema (initial placeholder)
create extension if not exists "uuid-ossp";

create table if not exists projects_biz (
    id uuid primary key default uuid_generate_v4(),
    tenant_id uuid not null,
    name varchar(200) not null,
    country varchar(100),
    sector varchar(100),
    languages text,
    codebook jsonb,
    odk_project_id bigint,
    odk_project_uuid uuid,
    odk_xml_form_id varchar(200),
    status varchar(50) default 'DRAFT',
    created_by uuid not null,
    created_at timestamp without time zone default now(),
    deleted_at timestamp without time zone,
    deleted_by uuid
);

create table if not exists project_forms (
    id uuid primary key default uuid_generate_v4(),
    project_id uuid not null references projects_biz(id) on delete cascade,
    template_name varchar(200),
    version varchar(50),
    uploaded_at timestamp without time zone default now()
);

create table if not exists project_integrations (
    id uuid primary key default uuid_generate_v4(),
    project_id uuid not null references projects_biz(id) on delete cascade,
    type varchar(50) not null,
    payload jsonb
);

create table if not exists form_templates (
    id uuid primary key default uuid_generate_v4(),
    name varchar(150) not null,
    description varchar(255),
    json_spec jsonb not null
);

